const KOMMO_DOMAIN = 'helloshkolaonlinecom.kommo.com';

function get(path) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: KOMMO_DOMAIN,
      path,
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + KOMMO_TOKEN }
    };
    https.get(options, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve(JSON.parse(data)));
    }).on('error', reject);
  });
}

async function main() {
  const dealId = 18287787;
  const res = await get(`/api/v4/leads/${dealId}/notes?limit=50&with=created_by`);
  const notes = res?._embedded?.notes || [];
  
  console.log(`Нот в сделке ${dealId}: ${notes.length}`);
  console.log('');
  
  for (const n of notes) {
    const date = new Date(n.created_at * 1000).toISOString().slice(0, 19).replace('T', ' ');
    const text = n.params?.text || n.params?.service?.comment || JSON.stringify(n.params).slice(0, 80);
    console.log(`[${n.id}] type=${n.note_type} created=${date}`);
    console.log(`  text: ${text}`);
    console.log('');
  }
}

main().catch(console.error);
